def main():
    with open(TARGET, "r", encoding="utf-8") as f:
        d = json.load(f)

    total_replaced = 0
    weeks_updated = []
    for week_entry in d["11"]:
        wk = week_entry["week"]
        if wk not in QS:
            continue
        qlist = QS[wk]
        assert len(qlist) == 25, f"wk{wk} has {len(qlist)} questions, expected 25"
        new_questions = []
        for i, (q, opts, ans) in enumerate(qlist, 1):
            assert len(opts) == 4, f"wk{wk} q{i} has {len(opts)} options"
            assert ans in opts, f"wk{wk} q{i} answer {ans!r} not in options"
            new_questions.append({
                "id": f"c11-w{wk}-q{i}",
                "question": q,
                "options": opts,
                "answer": ans,
            })
        week_entry["questions"] = new_questions
        total_replaced += len(new_questions)
        weeks_updated.append(wk)

    with open(TARGET, "w", encoding="utf-8") as f:
        f.write(json.dumps(d, indent=2, ensure_ascii=False) + "\n")

    print(f"Replaced {total_replaced} chemistry/11 placeholder questions across {len(weeks_updated)} weeks: {weeks_updated}")

if __name__ == "__main__":
    main()
